// NEVER use in production
function calcEval(a, b, op) {
  return eval(`${a} ${op} ${b}`);
}

function calcBigInt(a, b, op) {
  const A = BigInt(a), B = BigInt(b);
  switch (op) {
    case '+': return Number(A + B);
    case '-': return Number(A - B);
    case '*': return Number(A * B);
    case '/': return Number(A / B);
    default: return NaN;
  }
}
